package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.AssignExpr;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        Path filePath = Paths.get(args[0]);
        CompilationUnit cu = StaticJavaParser.parse(filePath);

        // Remove the problematic import
        cu.getImports().removeIf(importDecl -> 
            importDecl.getNameAsString().equals("com.gargoylesoftware.htmlunit.ScriptResult"));

        // Process all variable declarations and method calls
        cu.findAll(VariableDeclarator.class).forEach(varDecl -> {
            varDecl.getInitializer().ifPresent(init -> {
                if (init instanceof ObjectCreationExpr) {
                    ObjectCreationExpr oce = (ObjectCreationExpr) init;
                    if (oce.getType().asString().equals("ScriptResult")) {
                        // Replace: ScriptResult scriptResult = new ScriptResult(result);
                        // With: Object scriptResult = result;
                        oce.getParentNode().ifPresent(parent -> {
                            if (parent instanceof VariableDeclarationExpr) {
                                VariableDeclarationExpr vde = (VariableDeclarationExpr) parent;
                                vde.getElement(0).setType("Object");
                                varDecl.setInitializer(oce.getArgument(0));
                            }
                        });
                    }
                }
            });
        });

        // Replace .getJavaScriptResult() calls - remove the method call, keep the receiver
        cu.findAll(MethodCallExpr.class).forEach(methodCall -> {
            if (methodCall.getNameAsString().equals("getJavaScriptResult")) {
                methodCall.getParentNode().ifPresent(parent -> {
                    if (parent instanceof ExpressionStmt) {
                        ExpressionStmt stmt = (ExpressionStmt) parent;
                        methodCall.getScope().ifPresent(scope -> {
                            stmt.replace(new NameExpr(scope.toString()));
                        });
                    } else if (parent instanceof MethodCallExpr) {
                        MethodCallExpr parentCall = (MethodCallExpr) parent;
                        methodCall.getScope().ifPresent(scope -> {
                            parentCall.setScope(scope);
                        });
                    }
                });
            }
        });

        String result = cu.toString();
        Files.write(filePath, result.getBytes());
        System.out.println("Transformation applied successfully to: " + filePath);
    }
}

