package io.jenkins.plugins.coverage.util;

import org.openqa.selenium.By;
import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.WebElement;

import org.jenkinsci.test.acceptance.po.PageObject;

/**
 * Charts are displayed one multiple PageObjects. This util provides some helper methods to deal with charts.
 */
@SuppressWarnings("hideutilityclassconstructor")
// TODO: Move this code to ATH so we can reuse it from other plugins
public class ChartUtil {
    private static final int MAX_ATTEMPTS = 5;

    /**
     * Returns a chart's data by its id.
     *
     * @param pageObject
     *         which contains chart
     * @param elementId
     *         of chart
     *
     * @return data as json
     */
    public static String getChartDataById(final PageObject pageObject, final String elementId) {
        if (isChartDisplayedByElementId(pageObject, elementId)) {
            Object result = pageObject.executeScript(String.format(
                    "delete(window.Array.prototype.toJSON) %n"
                            + "return JSON.stringify(echarts.getInstanceByDom(document.getElementById(\"%s\")).getOption())",
                    elementId));
            return result.toString();
        }
        return null;
    }

    /**
     * Returns data of only chart with given tool attribute value on page.
     *
     * @param pageObject
     *         which contains only one chart with given tool attribute value
     * @param toolAttribute
     *         value in div tag of chart
     *
     * @return data as json
     */
    public static String getDataOfOnlyChartOnPageWithGivenToolAttribute(final PageObject pageObject,
            final String toolAttribute) {
        if (isChartDisplayedByDivToolAttribute(pageObject, toolAttribute)) {
            for (int i = 0; i < MAX_ATTEMPTS; i++) {
                Object result = pageObject.executeScript(String.format(
                        "delete(window.Array.prototype.toJSON) %n"
                                + "return JSON.stringify(echarts.getInstanceByDom(document.querySelector(\"div [tool='%s']\")).getOption())",
                        toolAttribute));

                if (result != null) {
                    return result.toString();
                }
                pageObject.elasticSleep(1000);
            }
        }
        throw new java.util.NoSuchElementException("Found no trend chart with ID '%s''" + toolAttribute);
    }

    /**
     * Returns if chart is displayed.
     *
     * @param pageObject
     *         which contains chart
     * @param elementId
     *         of chart
     *
     * @return if chart is displayed
     */
    public static boolean isChartDisplayedByElementId(final PageObject pageObject, final String elementId) {
        try {
            WebElement chart = pageObject.find(By.id(elementId));
            return chart != null && chart.isDisplayed();
        }
        catch (NoSuchElementException exception) {
            return false;
        }
    }

    /**
     * Returns if a chart with given tool attribute in div tag is displayed.
     *
     * @param pageObject
     *         which contains chart
     * @param toolAttribute
     *         of div tag of chart
     *
     * @return if chart is displayed
     */
    public static boolean isChartDisplayedByDivToolAttribute(final PageObject pageObject, final String toolAttribute) {
        try {
            WebElement chart = pageObject.find(By.cssSelector("div[tool='" + toolAttribute + "']"));
            return chart != null && chart.isDisplayed();
        }
        catch (NoSuchElementException exception) {
            return false;
        }

    }

}

package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.ArrayList;

/**
 * JavaParser transformation to fix ScriptResult compilation errors.
 * 
 * This transformation:
 * 1. Removes the import for com.gargoylesoftware.htmlunit.ScriptResult
 * 2. Replaces "new ScriptResult(x)" with just "x"
 * 3. Removes calls to ".getJavaScriptResult()" by replacing with the receiver
 * 4. Simplifies variable declarations that used ScriptResult wrapper
 */
public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <path-to-java-file>");
            System.exit(1);
        }

        Path filePath = Paths.get(args[0]);
        CompilationUnit cu = StaticJavaParser.parse(filePath);

        // Remove the problematic import
        cu.getImports().removeIf(importDecl -> 
            importDecl.getNameAsString().equals("com.gargoylesoftware.htmlunit.ScriptResult"));

        // First pass: collect all ObjectCreationExpr of ScriptResult that need replacement
        List<ObjectCreationExpr> toReplace = new ArrayList<>();
        cu.findAll(ObjectCreationExpr.class).forEach(oce -> {
            if (oce.getType().asString().equals("ScriptResult")) {
                toReplace.add(oce);
            }
        });

        // Replace ScriptResult constructor calls with their argument
        for (ObjectCreationExpr oce : toReplace) {
            if (oce.getArguments().size() == 1) {
                oce.replace(oce.getArgument(0));
            }
        }

        // Second pass: collect all getJavaScriptResult() method calls
        List<MethodCallExpr> toRemove = new ArrayList<>();
        cu.findAll(MethodCallExpr.class).forEach(methodCall -> {
            if (methodCall.getNameAsString().equals("getJavaScriptResult")) {
                toRemove.add(methodCall);
            }
        });

        // Remove getJavaScriptResult() calls by replacing with scope
        for (MethodCallExpr methodCall : toRemove) {
            methodCall.getScope().ifPresent(scope -> {
                methodCall.replace(scope);
            });
        }

        // Third pass: simplify variable declarations where initializer is now a simple expression
        cu.findAll(VariableDeclarator.class).forEach(varDecl -> {
            varDecl.getInitializer().ifPresent(init -> {
                // If the variable type was ScriptResult, change it to Object
                if (varDecl.getTypeAsString().equals("ScriptResult")) {
                    varDecl.setType("Object");
                }
            });
        });

        String result = cu.toString();
        Files.write(filePath, result.getBytes());
        System.out.println("Transformation applied successfully to: " + filePath);
    }
}
